import type { Post, ServiceFaq } from "@/lib/content/types";
import { getBlogImage } from "@/lib/content/blog-images";
import {
  buildPostFooter,
  defaultServiceLinks,
  estimateReadingTime,
} from "./posts/helpers";

type PostSeed = Omit<
  Post,
  "id" | "content" | "readingTime" | "featuredImage" | "status" | "isFeatured"
> & { featured?: boolean };

function createPost(
  index: number,
  bodyHtml: string,
  footerFaqs: ServiceFaq[],
  seed: PostSeed,
): Post {
  const content = bodyHtml + buildPostFooter(footerFaqs, defaultServiceLinks);
  return {
    id: String(index),
    featuredImage: index % 3 === 0 ? undefined : getBlogImage(index),
    status: "published",
    isFeatured: seed.featured ?? index <= 3,
    ...seed,
    content,
    readingTime: estimateReadingTime(content),
  };
}

const post1Body = `<p>Mỗi tuần tôi nhận không ít tin nhắn hỏi về bảng giá lắp WiFi VNPT 2026. Nhiều người xem bảng trên website hoặc qua Zalo rồi thắc mắc: sao giá mình được báo khác giá bạn bè? Thực tế, bảng giá WiFi VNPT không chỉ là một con số cước tháng — nó gồm nhiều thành phần và phụ thuộc địa chỉ lắp đặt. Bài viết này tôi tổng hợp cách đọc bảng giá đúng, tránh phát sinh và chọn gói phù hợp cho hộ gia đình tại TP.HCM, đặc biệt khu vực Quận 12 mà tôi hỗ trợ trực tiếp.</p><h2>Bảng giá WiFi VNPT gồm những khoản nào?</h2><p>Khi nhìn bảng giá, đa số khách chỉ chú ý cột tốc độ và giá tháng. Tôi thường giải thích thêm ba nhóm chi phí chính để tránh hiểu nhầm sau này.</p><h3>Cước hàng tháng</h3><p>Đây là khoản bạn trả định kỳ mỗi tháng theo gói đã chọn — 300 Mbps, 500 Mbps, 1 Gbps… Giá niêm yết trên bảng thường áp dụng khi trả cước đủ 12 tháng hoặc theo chương trình khuyến mãi từng thời điểm. Nếu trả theo tháng lẻ, cước có thể cao hơn vài chục nghìn so với cam kết dài hạn. Tôi khuyên so sánh tổng chi phí cả năm thay vì chỉ nhìn tháng đầu.</p><h3>Phí hòa mạng</h3><p>Phí hòa mạng thu một lần khi đăng ký mới. Một số đợt khuyến mãi miễn phí hòa mạng hoặc giảm 50–100%. Tôi luôn ghi rõ con số này trong tin nhắn tư vấn vì đây là khoản khách hay bất ngờ nhất nếu không được báo trước. Khi so sánh giữa hai nhà mạng, nhớ cộng phí hòa mạng vào tổng chi phí năm đầu.</p><h3>Thiết bị và dịch vụ bổ sung</h3><p>Modem WiFi thường đi kèm gói Internet. Nếu nhà rộng, nhiều tầng, bạn có thể cần thêm WiFi Mesh — chi phí thuê hoặc mua node Mesh tính riêng. Camera, combo di động cũng có bảng giá riêng, không nằm trong cước Internet cơ bản. Đừng nhầm giá Internet thuần với combo trọn gói.</p><h2>Giá nội thành và ngoại thành — đọc đúng cột nào?</h2><p>TP.HCM trên bảng giá VNPT thường chia nội thành và ngoại thành. Quận 12 thuộc nội thành, nên khi so sánh giá bạn cần nhìn cột nội thành, không lấy giá ngoại thành của Bình Dương hay Long An để đối chiếu.</p><p>Tôi hay gặp trường hợp khách chuyển nhà từ quận trung tâm sang Quận 12, nghĩ giá sẽ giảm — thực tế vẫn là mức nội thành. Ngược lại, ai lắp ở huyện ngoại thành nhưng xem nhầm bảng nội thành sẽ thất vọng khi nhận hóa đơn. Cách chắc chắn nhất: gửi địa chỉ cụ thể (số nhà, đường, phường) để kiểm tra hạ tầng và mức giá áp dụng.</p><h2>Cách đọc bảng giá theo nhu cầu thực tế</h2><p>Bảng giá liệt kê nhiều gói tốc độ. Tôi gợi ý chọn theo số người và thiết bị, không chọn gói cao nhất mặc định.</p><ul><li><strong>1–3 người, 5–8 thiết bị:</strong> 300 Mbps thường đủ cho lướt web, học online, xem phim HD.</li><li><strong>4–6 người, nhiều TV/camera:</strong> 500 Mbps cân bằng giá và trải nghiệm.</li><li><strong>Livestream, làm việc từ xa nặng, văn phòng nhỏ:</strong> cân nhắc 1 Gbps.</li></ul><p>Nhà 2–3 tầng dù chọn gói cao vẫn có thể WiFi yếu ở xa modem — khi đó cần Mesh chứ không phải nâng gói Internet. Tôi thường khảo sát miễn phí trước khi khuyên nâng cước, vì nhiều khách tiết kiệm được bằng cách đặt modem đúng chỗ thay vì trả thêm hàng trăm nghìn mỗi tháng.</p><h2>Mẹo tiết kiệm khi xem bảng giá 2026</h2><p>Thứ nhất, so sánh tổng chi phí 12 tháng (cước × 12 + phí hòa mạng − khuyến mãi), không chỉ so tháng đầu. Thứ hai, hỏi rõ modem đi kèm loại gì, có WiFi 6 không. Thứ ba, nếu đã dùng di động VNPT, combo Internet + di động đôi khi rẻ hơn đăng ký rời.</p><p>Thứ tư, tránh cam kết gói quá cao chỉ vì khuyến mãi tặng tháng — khi hết khuyến mãi, cước gốc có thể cao hơn nhu cầu. Thứ năm, hỏi chính sách đổi gói giữa hợp đồng: một số khách đăng ký 1 Gbps rồi muốn hạ xuống 500 Mbps nhưng không rõ điều kiện.</p><h2>Những điều nên hỏi trước khi chốt</h2><p>Trước khi ký, tôi khuyên bạn xác nhận: thời gian lắp dự kiến, ai chịu phí nếu cần kéo thêm cáp, chính sách đổi gói giữa hợp đồng, và cách liên hệ khi sự cố. Bảng giá chỉ là điểm bắt đầu; trải nghiệm lắp đặt và hỗ trợ sau bán mới quyết định bạn có hài lòng lâu dài hay không.</p><p>Nếu bạn đang ở Quận 12 hoặc lân cận và cần bảng giá WiFi VNPT 2026 cập nhật theo địa chỉ nhà, cứ nhắn tôi — tôi gửi chi tiết từng khoản, không gói gọn chung chung. Tôi cũng sẵn sàng so sánh với nhu cầu thực tế để bạn không trả thừa cho băng thông không dùng hết.</p>`;

